UPDATE chat_room_state s
    JOIN (
    SELECT MAX(last_read_message_id) AS other_last_read
    FROM chat_room_state
    WHERE chat_room_id = #{roomId}
    AND member_id <> #{myId}
    ) x
SET s.last_read_message_id = GREATEST(s.last_read_message_id, x.other_last_read)
WHERE s.chat_room_id = #{roomId}
  AND s.member_id    = #{myId};

mapper.select:

SELECT
    m.chat_message_id AS id,
    m.sender_id       AS senderId,
    m.content         AS content,
    m.created_at      AS createdAt
FROM chat_message m
WHERE m.chat_room_id = #{roomId}
  AND m.chat_message_id < #{beforeId}
ORDER BY m.chat_message_id DESC
    LIMIT #{size}


SELECT s.member_id
FROM chat_room_state s
WHERE s.chat_room_id = #{roomId}
  AND s.member_id <> #{myId}
    LIMIT 1

