UPDATE chat_room_state
SET last_read_message_id = GREATEST(last_read_message_id, #{newId})
WHERE chat_room_id = #{roomId}
  AND member_id    = #{myId}

UPDATE chat_room_state
SET last_read_message_id = GREATEST(last_read_message_id, #{newId})
WHERE chat_room_id = #{roomId}
  AND member_id    = #{otherId}

mapper.select:
SELECT (s.last_read_message_id >= #{newId}) AS is_read
FROM chat_room_state s
WHERE s.chat_room_id = #{roomId}
  AND s.member_id    = #{otherId}

SELECT COUNT(*) > 0
FROM chat_room_state
WHERE chat_room_id = #{roomId}
  AND member_id    = #{myId}

SELECT m.chat_room_id AS chatRoomId, m.chat_message_id AS lastMessageId, CAST(m.sender_id AS CHAR) AS lastMessageSenderId, m.content AS lastMessageContent, m.created_at AS lastMessageAt FROM chat_message m INNER JOIN ( SELECT chat_room_id, MAX(chat_message_id) AS last_id FROM chat_message WHERE chat_room_id IN
#{roomId}
GROUP BY chat_room_id ) lm ON m.chat_room_id = lm.chat_room_id AND m.chat_message_id = lm.last_id

SELECT s.chat_room_id AS roomId, COUNT(*) AS unreadCount FROM chat_room_state s JOIN chat_message m ON m.chat_room_id = s.chat_room_id AND m.chat_message_id > COALESCE(s.last_read_message_id, 0) AND m.sender_id <> #{myId} WHERE s.member_id = #{myId} AND s.chat_room_id IN
#{roomId}
GROUP BY s.chat_room_id
